import os
from urllib import request
import base64
from datetime import datetime, timezone
from botocore.config import Config
import boto3  # version 1.9.80
import json
import logging


class BotoLogger(object):
    logger = None

    def __init__(self):
        self._setup_logger()
        self.__class__.logger = self._get_logger("root")


    @staticmethod
    def _get_logger(name):
        '''
            Configure the logging parameters.
        '''

        config = {
            'version': 1,
            'formatters': {'default': {
                'format': '%(asctime)s.%(msecs)03d %(levelname)-5.5s [%(name)s] - %(message)s',
                'datefmt': "%Y-%m-%d %H:%M:%S"
            }, },

            'handlers': {'file': {
                'class': 'logging.FileHandler',
                'formatter': 'default',
                'filename': './logs/aws-lambda-function-v01-{}.log'.format(datetime.now().strftime("%Y%m%d")),
                'mode': 'a+',
            },
                        }
        }

        logging.config.dictConfig(config)
        return logging.getLogger(name).getChild("boto_logger")

    def _setup_logger(self):
        '''
            Setting the log path with date/time.
        '''

        os.makedirs('logs', exist_ok=True)


def process_file(file, content, logger):
    try:
        image = open(file, 'r+b')
        imgByteArr = bytearray(image.read())
        imageBytes = base64.encodebytes(imgByteArr).decode('utf-8')

        body = {
            "content": imageBytes
        }

        json_response = json.dumps(body)
        logger.info("Image Content:\n{}".format(json_response))

        sns_client = boto3.client('sns', config=Config(signature_version='v4'))  # version 1.7.85
        topic_arn = os.environ['TOPIC_ARN']

        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json_response
        )

        logger.info('Response: {}'.format(response))

    except Exception as ex:
        logger.error("Error in processing file {} : {}".format(file, str(ex)))
    finally:
        image.close()


def lambda_handler(event, context):

    logger = BotoLogger().logger  # type: logging.Logger


    bucket_name = os.environ['S3_INPUT']
    s3 = boto3.resource('s3', config=Config(signature_version='v4'))  # version 1.9.80

    try:
        for object in s3.Bucket(bucket_name).objects.all():
            filename, file_extn = os.path.splitext(object.key)

            # Ignore the files that are not image or videos.
            if ('.jpg' != file_extn and '.png' != file_extn):
                continue

            s3Object = s3.Object(bucket_name, object.key).get()  # version 1.9.80
            file = open('{}'.format(filename), 'wb')
            try:
                file.write(s3Object['Body'].read())

                process_file('{}-{}'.format(datetime.now().strftime("%Y%m%d-%H%M%S"), filename),
                            '{}'.format(filename), logger)

            finally:
                file.close()

    except Exception as ex:
        logger.error("Error in lambda_handler : {}".format(str(ex)))
    else:
        return 0


if __name__ == '__main__':
    logging.basicConfig(level=logging.DEBUG)

    lambda_handler(event={}, context={'memory': {}, 'function': 'lambda',})